namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    #region CalculateTotal — DataRow tests

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(25.00, 2, 0.10, 55.00, DisplayName = "Two items with 10% tax")]
    [DataRow(99.99, 3, 0.20, 359.964, DisplayName = "Three items with 20% tax")]
    [DataRow(0.00, 10, 0.15, 0.00, DisplayName = "Zero price yields zero total")]
    [DataRow(50.00, 0, 0.10, 0.00, DisplayName = "Zero quantity yields zero total")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "100% tax doubles the price")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price throws")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below 0 throws")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1 throws")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    #endregion

    #region ApplyDiscount — DynamicData tests

    public static IEnumerable<object[]> DiscountTestCases
    {
        get
        {
            yield return new object[] { 200.00m, 0m, 200.00m, "No discount leaves price unchanged" };
            yield return new object[] { 200.00m, 50m, 100.00m, "50% discount halves the price" };
            yield return new object[] { 200.00m, 100m, 0.00m, "100% discount makes price zero" };
            yield return new object[] { 79.99m, 25m, 59.9925m, "25% off fractional price" };
            yield return new object[] { 0.00m, 50m, 0.00m, "Zero price stays zero regardless of discount" };
            yield return new object[] { 1000.00m, 10m, 900.00m, "10% off a large amount" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(DiscountTestCases))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result, $"Failed for scenario: {scenario}");
    }

    public static IEnumerable<object[]> InvalidDiscountTestCases()
    {
        yield return new object[] { 100.00m, -1m, "Negative discount" };
        yield return new object[] { 100.00m, 101m, "Discount exceeds 100%" };
        yield return new object[] { 50.00m, -0.01m, "Slightly negative discount" };
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountTestCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(
        decimal price, decimal discountPercent, string scenario)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent),
            $"Expected exception for scenario: {scenario}");
    }

    #endregion
}

